mapper.update:
update subscription_fulfillment_task
set status = 'PROCESSING', update_time = now()
where order_id = #{orderId}
  and service_package_id = #{servicePackageId}
  and (
      status in ('PENDING', 'RETRY')
      and (next_retry_time is null or next_retry_time <= now())
      or (status = 'PROCESSING' and update_time < date_sub(now(), interval 5 second))
  )

update subscription_fulfillment_task
set status = 'SUCCESS',
    fail_reason = null,
    update_time = now()
where order_id = #{orderId}
  and service_package_id = #{servicePackageId}

mapper.select:
select id, order_id, user_id, service_package_id, total_quota, status, retry_count, fail_reason, next_retry_time, create_time, update_time
from subscription_fulfillment_task
where order_id = #{orderId}
  and service_package_id = #{servicePackageId}
limit 1
